import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    max_distance_difference = -np.inf
    next_node = None

    for node in unvisited_nodes:
        if node not in truck_nodes:
            distance_to_node = distance_matrix[current_node][node]
            total_distance = sum([distance_matrix[current_node][n] for n in unvisited_nodes if n != node]) + distance_matrix[node][depot_node]
            distance_difference = total_distance - distance_to_node

            if distance_difference > max_distance_difference:
                max_distance_difference = distance_difference
                next_node = node

    return next_node
